using System;
using System.Collections.Generic;
using TMPro;
using UnityEngine;
using UnityEngine.EventSystems;
using UnityEngine.UI;

/// <summary>
/// Secção "Itens e Instintos" do Menu de Pausa (Tarefa #10) — duas listas
/// menores, propositadamente separadas para não misturar consumíveis com
/// melhorias permanentes/configuráveis:
///
/// CONSUMÍVEIS (<see cref="allConsumables"/>):
/// - Cada linha mostra ícone, nome e quantidade (PlayerProgress.GetItemQuantity).
/// - Itens com quantidade 0 aparecem cinzentos (ainda não encontrados/sem stock).
/// - Ao seleccionar, o painel central mostra nome, quantidade, descrição e
///   "A — Equipar"/"A — Desequipar".
/// - "A" equipa/desequipa directamente (PlayerProgress.EquipItem) — só itens
///   com quantidade > 0 podem ser equipados.
///
/// INSTINTOS (<see cref="allInstincts"/>):
/// - Só mostra upgrades já desbloqueados (PlayerProgress.HasUpgrade).
/// - Upgrades "toggleable" (UpgradeData.toggleable) têm um interruptor em
///   forma de semente: fechada = desligado, aberta = ligado
///   (<see cref="seedClosedSprite"/>/<see cref="seedOpenSprite"/>). "A" liga/
///   desliga (PlayerProgress.SetUpgradeEnabled).
/// - Upgrades permanentes (toggleable == false) mostram a semente sempre
///   aberta, sem interacção — "sempre activo depois de desbloqueado".
///
/// Montagem no Editor:
/// - "allConsumables"/"allInstincts": todos os ItemData/UpgradeData candidatos
///   a aparecer aqui (a lista filtra automaticamente o que ainda não foi
///   desbloqueado, no caso dos Instintos).
/// - "consumableRowPrefab"/"instinctRowPrefab": prefabs com
///   <see cref="ConsumableRowUI"/>/<see cref="InstinctRowUI"/> + Button, para
///   navegação e selecção por D-pad/teclado.
/// </summary>
public class ItemsInstinctsSectionUI : MonoBehaviour, IPauseMenuSection
{
    [Header("Framework")]
    [SerializeField] private GameObject root;

    [Header("Consumíveis")]
    [SerializeField] private List<ItemData> allConsumables = new List<ItemData>();
    [SerializeField] private Transform consumablesContainer;
    [SerializeField] private ConsumableRowUI consumableRowPrefab;

    [Tooltip("Cor do ícone/nome quando a quantidade do item é 0 (ainda não encontrado).")]
    [SerializeField] private Color emptyConsumableColor = new Color(1f, 1f, 1f, 0.4f);

    [Header("Detalhe do Consumível (centro)")]
    [SerializeField] private GameObject consumableDetailRoot;
    [SerializeField] private TMP_Text consumableNameText;
    [SerializeField] private string consumableNameFormat = "{0}    {1}";
    [SerializeField] private TMP_Text consumableDescriptionText;
    [SerializeField] private TMP_Text consumableActionHintText;
    [SerializeField] private string equipHint = "A — Equipar";
    [SerializeField] private string unequipHint = "A — Desequipar";

    [Header("Instintos")]
    [SerializeField] private List<UpgradeData> allInstincts = new List<UpgradeData>();
    [SerializeField] private Transform instinctsContainer;
    [SerializeField] private InstinctRowUI instinctRowPrefab;
    [SerializeField] private Sprite seedClosedSprite;
    [SerializeField] private Sprite seedOpenSprite;

    [Header("Sons")]
    [SerializeField] private AudioClip equipSfx;
    [SerializeField] private AudioClip toggleSfx;

    [Header("Estado Vazio")]
    [SerializeField] private GameObject emptyState;
    [SerializeField] private string emptyText = "Nada para mostrar ainda.";

    private readonly List<GameObject> spawnedConsumables = new List<GameObject>();
    private readonly List<GameObject> spawnedInstincts = new List<GameObject>();

    public string SectionName => "ITENS";
    public GameObject Root => root != null ? root : gameObject;

    public void Refresh()
    {
        ClearSpawned();

        var progress = PlayerProgress.Instance;

        ConsumableRowUI firstConsumableRow = null;
        ItemData firstConsumable = null;

        foreach (var item in allConsumables)
        {
            if (item == null || consumableRowPrefab == null || consumablesContainer == null) continue;

            int quantity = progress != null ? progress.GetItemQuantity(item) : 0;
            bool equipped = progress != null && progress.HasItemEquipped(item);

            var row = Instantiate(consumableRowPrefab, consumablesContainer);
            row.gameObject.SetActive(true);
            row.Setup(item, quantity, equipped, emptyConsumableColor, ShowConsumableDetails, ToggleEquip);

            spawnedConsumables.Add(row.gameObject);

            if (firstConsumableRow == null)
            {
                firstConsumableRow = row;
                firstConsumable = item;
            }
        }

        foreach (var upgrade in allInstincts)
        {
            if (upgrade == null || instinctRowPrefab == null || instinctsContainer == null) continue;
            if (progress == null || !progress.HasUpgrade(upgrade)) continue; // só upgrades já desbloqueados.

            bool enabled = progress.IsUpgradeEnabled(upgrade);

            var row = Instantiate(instinctRowPrefab, instinctsContainer);
            row.gameObject.SetActive(true);
            row.Setup(upgrade, enabled, seedClosedSprite, seedOpenSprite, ToggleInstinct);

            spawnedInstincts.Add(row.gameObject);
        }

        bool anyContent = spawnedConsumables.Count > 0 || spawnedInstincts.Count > 0;

        if (emptyState != null)
        {
            emptyState.SetActive(!anyContent);

            if (!anyContent)
            {
                var emptyTextComponent = emptyState.GetComponentInChildren<TMP_Text>();
                if (emptyTextComponent != null) emptyTextComponent.text = emptyText;
            }
        }

        if (firstConsumable != null)
        {
            ShowConsumableDetails(firstConsumable);
            if (EventSystem.current != null) EventSystem.current.SetSelectedGameObject(firstConsumableRow.gameObject);
        }
        else if (consumableDetailRoot != null)
        {
            consumableDetailRoot.SetActive(false);
        }
    }

    public void OnHide()
    {
        // Sem estado próprio a limpar — Refresh() reconstrói as listas na próxima vez.
    }

    // ---------------- Consumíveis ----------------

    private void ShowConsumableDetails(ItemData item)
    {
        if (item == null) return;

        var progress = PlayerProgress.Instance;
        int quantity = progress != null ? progress.GetItemQuantity(item) : 0;
        bool equipped = progress != null && progress.HasItemEquipped(item);

        if (consumableDetailRoot != null) consumableDetailRoot.SetActive(true);

        if (consumableNameText != null)
            consumableNameText.text = string.Format(consumableNameFormat, item.displayName.ToUpperInvariant(), quantity);

        if (consumableDescriptionText != null) consumableDescriptionText.text = item.description;

        if (consumableActionHintText != null)
            consumableActionHintText.text = equipped ? unequipHint : equipHint;
    }

    private void ToggleEquip(ItemData item)
    {
        var progress = PlayerProgress.Instance;
        if (progress == null || item == null) return;

        // Só é possível equipar itens que o jogador já possui.
        if (!progress.HasItemEquipped(item) && progress.GetItemQuantity(item) <= 0) return;

        if (progress.HasItemEquipped(item)) progress.EquipItem(null);
        else progress.EquipItem(item);

        PauseMenuController.Instance?.PlaySfx(equipSfx);
        ShowConsumableDetails(item);
    }

    // ---------------- Instintos ----------------

    private void ToggleInstinct(UpgradeData upgrade)
    {
        var progress = PlayerProgress.Instance;
        if (progress == null || upgrade == null || !upgrade.toggleable) return;

        bool newValue = !progress.IsUpgradeEnabled(upgrade);
        progress.SetUpgradeEnabled(upgrade, newValue);

        PauseMenuController.Instance?.PlaySfx(toggleSfx);
    }

    // ---------------- Limpeza ----------------

    private void ClearSpawned()
    {
        foreach (var go in spawnedConsumables)
            if (go != null) Destroy(go);
        spawnedConsumables.Clear();

        foreach (var go in spawnedInstincts)
            if (go != null) Destroy(go);
        spawnedInstincts.Clear();
    }
}

/// <summary>
/// Linha de um consumível na lista "Itens e Instintos" (ItemsInstinctsSectionUI).
/// Mostra ícone, nome e quantidade; "A" equipa/desequipa directamente.
/// </summary>
public class ConsumableRowUI : MonoBehaviour, ISelectHandler
{
    [SerializeField] private Image iconImage;
    [SerializeField] private TMP_Text nameText;
    [SerializeField] private TMP_Text quantityText;
    [SerializeField] private GameObject equippedMarker;

    private ItemData item;
    private Action<ItemData> onSelected;
    private Action<ItemData> onEquip;

    public void Setup(ItemData item, int quantity, bool equipped, Color emptyColor, Action<ItemData> onSelected, Action<ItemData> onEquip)
    {
        this.item = item;
        this.onSelected = onSelected;
        this.onEquip = onEquip;

        if (nameText != null) nameText.text = item.displayName;
        if (quantityText != null) quantityText.text = quantity.ToString();

        if (iconImage != null)
        {
            iconImage.sprite = item.icon;
            iconImage.enabled = item.icon != null;
        }

        bool empty = quantity <= 0;
        var color = empty ? emptyColor : Color.white;
        if (nameText != null) nameText.color = color;
        if (quantityText != null) quantityText.color = color;
        if (iconImage != null) iconImage.color = color;

        if (equippedMarker != null) equippedMarker.SetActive(equipped);

        var button = GetComponent<Button>();
        if (button != null)
        {
            button.onClick.RemoveAllListeners();
            button.onClick.AddListener(() => this.onEquip?.Invoke(this.item));
        }
    }

    public void OnSelect(BaseEventData eventData)
    {
        onSelected?.Invoke(item);
    }
}

/// <summary>
/// Linha de um Instinto na lista "Itens e Instintos" (ItemsInstinctsSectionUI).
/// Mostra ícone, nome e o interruptor em forma de semente (fechada/aberta).
/// Upgrades não-"toggleable" mostram a semente sempre aberta, sem interacção.
/// </summary>
public class InstinctRowUI : MonoBehaviour
{
    [SerializeField] private Image iconImage;
    [SerializeField] private TMP_Text nameText;
    [SerializeField] private Image seedImage;

    private UpgradeData upgrade;
    private Sprite closedSprite;
    private Sprite openSprite;
    private Action<UpgradeData> onToggle;

    public void Setup(UpgradeData upgrade, bool enabled, Sprite closedSprite, Sprite openSprite, Action<UpgradeData> onToggle)
    {
        this.upgrade = upgrade;
        this.closedSprite = closedSprite;
        this.openSprite = openSprite;
        this.onToggle = onToggle;

        if (nameText != null) nameText.text = upgrade.displayName;

        if (iconImage != null)
        {
            iconImage.sprite = upgrade.icon;
            iconImage.enabled = upgrade.icon != null;
        }

        // Upgrades permanentes (não-toggleable) mostram a semente sempre aberta.
        bool open = !upgrade.toggleable || enabled;
        UpdateSeed(open);

        var button = GetComponent<Button>();
        if (button != null)
        {
            button.onClick.RemoveAllListeners();
            if (upgrade.toggleable) button.onClick.AddListener(HandleToggle);

            button.interactable = upgrade.toggleable;
        }
    }

    private void HandleToggle()
    {
        onToggle?.Invoke(upgrade);

        var progress = PlayerProgress.Instance;
        bool open = progress != null && progress.IsUpgradeEnabled(upgrade);
        UpdateSeed(open);
    }

    private void UpdateSeed(bool open)
    {
        if (seedImage == null) return;

        seedImage.sprite = open ? openSprite : closedSprite;
        seedImage.enabled = seedImage.sprite != null;
    }
}
